import React, { useState, useEffect } from 'react';
import axios from 'axios';

const TestDriveManagement = () => {
  const [testDrives, setTestDrives] = useState([]);
  const [loading, setLoading] = useState(true);
  const [filter, setFilter] = useState('all');

  useEffect(() => {
    fetchTestDrives();
  }, []);

  const fetchTestDrives = async () => {
    try {
      const res = await axios.get('http://localhost:5000/api/admin/testdrives');
      setTestDrives(res.data);
      setLoading(false);
    } catch (error) {
      console.error('Lỗi tải lịch lái thử:', error);
      setLoading(false);
    }
  };

  const handleStatusChange = async (id, newStatus) => {
    try {
      await axios.put(`http://localhost:5000/api/admin/testdrives/${id}/status`, { status: newStatus });
      alert('Cập nhật trạng thái thành công!');
      fetchTestDrives();
    } catch (error) {
      alert('Lỗi: ' + (error.response?.data?.message || 'Cập nhật thất bại'));
    }
  };

  const formatDate = (dateString) => {
    return new Date(dateString).toLocaleDateString('vi-VN');
  };

  const getStatusBadge = (status) => {
    const badges = {
      pending: { text: '⏳ Chờ xác nhận', class: 'badge-pending' },
      confirmed: { text: '✅ Đã xác nhận', class: 'badge-confirmed' },
      completed: { text: '✔️ Đã hoàn thành', class: 'badge-completed' },
      cancelled: { text: '❌ Đã hủy', class: 'badge-cancelled' }
    };
    return badges[status] || badges.pending;
  };

  const filteredDrives = testDrives.filter(drive => {
    if (filter === 'all') return true;
    return drive.status === filter;
  });

  if (loading) return <div className="loading">Đang tải...</div>;

  return (
    <div>
      <h1>Quản lý lịch lái thử</h1>

      {/* Bộ lọc */}
      <div style={{ marginBottom: '20px', display: 'flex', gap: '10px' }}>
        <select 
          value={filter} 
          onChange={(e) => setFilter(e.target.value)}
          style={{
            padding: '10px',
            borderRadius: '5px',
            border: '1px solid #ddd'
          }}
        >
          <option value="all">📋 Tất cả</option>
          <option value="pending">⏳ Chờ xác nhận</option>
          <option value="confirmed">✅ Đã xác nhận</option>
          <option value="completed">✔️ Đã hoàn thành</option>
          <option value="cancelled">❌ Đã hủy</option>
        </select>
        
        <span style={{ padding: '10px', color: '#666' }}>
          Tổng: {filteredDrives.length} lịch hẹn
        </span>
      </div>

      {/* Bảng lịch lái thử */}
      <table className="admin-table">
        <thead>
          <tr>
            <th>ID</th>
            <th>Khách hàng</th>
            <th>Xe</th>
            <th>SĐT</th>
            <th>Ngày hẹn</th>
            <th>Giờ</th>
            <th>Trạng thái</th>
            <th>Ngày đặt</th>
            <th>Thao tác</th>
          </tr>
        </thead>
        <tbody>
          {filteredDrives.map(drive => {
            const status = getStatusBadge(drive.status);
            return (
              <tr key={drive.id}>
                <td>{drive.id}</td>
                <td>
                  <strong>{drive.fullname}</strong>
                  <br />
                  <small>{drive.email}</small>
                </td>
                <td>{drive.car_name || 'Không xác định'}</td>
                <td>{drive.phone}</td>
                <td>{formatDate(drive.test_date)}</td>
                <td>{drive.test_time}</td>
                <td>
                  <select
                    value={drive.status}
                    onChange={(e) => handleStatusChange(drive.id, e.target.value)}
                    style={{
                      padding: '5px',
                      borderRadius: '3px',
                      border: '1px solid #ddd',
                      background: drive.status === 'pending' ? '#fff3cd' :
                                  drive.status === 'confirmed' ? '#d4edda' :
                                  drive.status === 'completed' ? '#cce5ff' : '#f8d7da'
                    }}
                  >
                    <option value="pending">⏳ Chờ xác nhận</option>
                    <option value="confirmed">✅ Đã xác nhận</option>
                    <option value="completed">✔️ Đã hoàn thành</option>
                    <option value="cancelled">❌ Đã hủy</option>
                  </select>
                </td>
                <td>{formatDate(drive.created_at)}</td>
                <td>
                  <button 
                    onClick={() => handleStatusChange(drive.id, 'cancelled')}
                    className="btn-delete"
                    disabled={drive.status === 'cancelled' || drive.status === 'completed'}
                  >
                    Hủy
                  </button>
                </td>
              </tr>
            );
          })}
        </tbody>
      </table>
    </div>
  );
};

export default TestDriveManagement;
